import{i as e,r as t,s as n,t as r}from"./app-DRIoFJCO.js";var i=JSON.parse(`{"path":"/docs/%E4%BB%80%E4%B9%88%E6%98%AF%E8%8A%82%E7%82%B9.html","title":"什么是节点？","lang":"zh-CN","frontmatter":{"description":"说明Dvnge视觉小说引擎的节点概念，节点是引擎的基本单位，可设置角色、内容、立绘、背景等一切属性。"},"filePathRelative":"docs/什么是节点.md","git":{"createdTime":1781703562000,"updatedTime":1781781922000,"contributors":[{"name":"TTQWNTian","username":"TTQWNTian","email":"ttqwntian@qq.com","commits":2,"url":"https://github.com/TTQWNTian"}]}}`),a={name:`什么是节点.md`};function o(r,i,a,o,s,c){return n(),t(`div`,null,[...i[0]||=[e(`<h1 id="什么是节点" tabindex="-1"><a class="header-anchor" href="#什么是节点"><span>什么是节点？</span></a></h1><p>节点简单来讲就是“这一段话”（虽然不太严谨吧），在节点里面可以设置这里要有什么文本、立绘、背景等等，用户每点击一下屏幕就会切换到下一个节点。</p><p>比如之前我们写的这个：</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token keyword">var</span> 示例 <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        <span class="token literal-property property">角色</span><span class="token operator">:</span> <span class="token string">&quot;Tian&quot;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token literal-property property">内容</span><span class="token operator">:</span> <span class="token string">&quot;你好，世界。&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>其中：</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token punctuation">{</span></span>
<span class="line">    <span class="token literal-property property">角色</span><span class="token operator">:</span> <span class="token string">&quot;Tian&quot;</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token literal-property property">内容</span><span class="token operator">:</span> <span class="token string">&quot;你好，世界。&quot;</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>就是一个节点。</p><p>那么我们在后面再加一个节点：</p><div class="language-javascript line-numbers-mode" data-highlighter="prismjs" data-ext="js"><pre><code class="language-javascript"><span class="line"><span class="token keyword">var</span> 示例 <span class="token operator">=</span> <span class="token punctuation">[</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        <span class="token literal-property property">角色</span><span class="token operator">:</span> <span class="token string">&quot;Tian&quot;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token literal-property property">内容</span><span class="token operator">:</span> <span class="token string">&quot;你好，世界。&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span><span class="token comment">// 注意：这里一定要加英文,号</span></span>
<span class="line">    <span class="token punctuation">{</span></span>
<span class="line">        <span class="token literal-property property">角色</span><span class="token operator">:</span> <span class="token string">&quot;Tian&quot;</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token literal-property property">内容</span><span class="token operator">:</span> <span class="token string">&quot;欢迎使用Dvnge~&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">]</span><span class="token punctuation">;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>运行 <code>game.html</code> 再点击一下屏幕就能看到切换对话了。</p>`,10)]])}var s=r(a,[[`render`,o]]);export{i as _pageData,s as default};